/**
 * Notification service — dispatches notifications via an EventBus channel pattern.
 *
 * Architecture:
 * - When domain events occur (order:created, order:status-changed), the service
 *   publishes a `notification:requested` event on the EventBus.
 * - Channel handlers (e.g., EmailChannelHandler) subscribe to `notification:requested`
 *   and deliver through their respective channel.
 * - This design is extensible: add new channel handlers (SMS, push, etc.) without
 *   modifying the notification service itself.
 *
 * Depends on:
 * - EventBus (event system) for both receiving domain events and dispatching notifications
 * - CallbackRegistry (direct callbacks) for order:status-changed events (legacy pattern)
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  NotificationRequestedEvent,
} from '../events/event-types.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';

export interface Notification {
  id: string;
  channel: string;
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

/**
 * Interface for notification channel handlers.
 * Implement this to add new delivery channels (email, SMS, push, etc.).
 */
export interface NotificationChannelHandler {
  readonly channel: string;
  handle(event: NotificationRequestedEvent): void;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

/**
 * Email channel handler — delivers notifications via email.
 * Subscribes to `notification:requested` events on the EventBus and processes
 * those targeted at the 'email' channel.
 */
export class EmailChannelHandler implements NotificationChannelHandler {
  readonly channel = 'email';
  private logger = new Logger('EmailChannelHandler');
  private deliveredEmails: Notification[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
      if (event.channel === this.channel) {
        this.handle(event);
      }
    });
  }

  handle(event: NotificationRequestedEvent): void {
    const notification: Notification = {
      id: generateNotificationId(),
      channel: this.channel,
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      sentAt: new Date(),
    };
    this.deliveredEmails.push(notification);
    this.logger.info(`Email sent: ${notification.id} to ${event.recipient}`);
  }

  getDeliveredEmails(): Notification[] {
    return [...this.deliveredEmails];
  }

  clearDeliveredEmails(): void {
    this.deliveredEmails = [];
  }
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register event handlers for notification triggers.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern).
   */
  private registerHandlers(): void {
    // Pattern 1: EventBus subscription for order creation
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    // Pattern 2: CallbackRegistry for status changes
    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });

    // Collect all dispatched notifications for tracking
    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
      const notification: Notification = {
        id: generateNotificationId(),
        channel: event.channel,
        recipient: event.recipient,
        subject: event.subject,
        body: event.body,
        sentAt: new Date(),
      };
      this.notifications.push(notification);
    });
  }

  /**
   * Handle order created event — dispatch email notification to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.dispatchNotification({
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — dispatch email notification to user.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.dispatchNotification({
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  /**
   * Dispatch a notification event on the EventBus.
   * Channel handlers subscribed to `notification:requested` will pick it up.
   */
  dispatchNotification(params: {
    channel: string;
    recipient: string;
    subject: string;
    body: string;
  }): void {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      timestamp: new Date(),
    };
    // Synchronous emit — handlers run inline since EventBus.emit is async
    // but our handlers are synchronous
    void this.eventBus.emit(event);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  EmailChannelHandler,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  NotificationRequestedEvent,
} from '../../src/events/event-types.js';

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    service = new NotificationService(eventBus);
    resetNotificationIdCounter();
  });

  describe('order:created handler', () => {
    it('should send notification on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('$20.00');
    });

    it('should include all items in notification body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('Gadget x1');
    });
  });

  describe('order:status-changed handler', () => {
    it('should send notification on status change', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Order Update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');
    });
  });

  describe('notification management', () => {
    it('should count notifications', () => {
      expect(service.getNotificationCount()).toBe(0);

      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(service.getNotificationCount()).toBe(1);
    });

    it('should filter by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
      expect(service.getNotificationsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear notifications', () => {
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      service.clearNotifications();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', () => {
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      expect(notifications[0]?.id).toBe('notif-0001');
      expect(notifications[1]?.id).toBe('notif-0002');
    });
  });

  describe('dispatchNotification', () => {
    it('should publish notification:requested event on EventBus', async () => {
      service.dispatchNotification({
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test Subject',
        body: 'Test body content',
      });

      // Allow async emit to complete
      await new Promise((resolve) => setTimeout(resolve, 0));

      const log = eventBus.getEventLog();
      const notifEvents = log.filter((e) => e.type === 'notification:requested');
      expect(notifEvents).toHaveLength(1);

      const event = notifEvents[0] as NotificationRequestedEvent;
      expect(event.channel).toBe('email');
      expect(event.recipient).toBe('test@example.com');
      expect(event.subject).toBe('Test Subject');
      expect(event.body).toBe('Test body content');
    });

    it('should track dispatched notifications', async () => {
      service.dispatchNotification({
        channel: 'sms',
        recipient: '+1234567890',
        subject: 'Alert',
        body: 'Test alert',
      });

      await new Promise((resolve) => setTimeout(resolve, 0));

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('sms');
      expect(notifications[0]?.recipient).toBe('+1234567890');
    });
  });
});

describe('EmailChannelHandler', () => {
  let eventBus: EventBus;
  let emailHandler: EmailChannelHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    resetNotificationIdCounter();
    emailHandler = new EmailChannelHandler(eventBus);
  });

  it('should deliver email notifications from EventBus', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Welcome',
      body: 'Welcome to TaskFlow Pro!',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const emails = emailHandler.getDeliveredEmails();
    expect(emails).toHaveLength(1);
    expect(emails[0]?.channel).toBe('email');
    expect(emails[0]?.recipient).toBe('alice@example.com');
    expect(emails[0]?.subject).toBe('Welcome');
    expect(emails[0]?.body).toBe('Welcome to TaskFlow Pro!');
  });

  it('should ignore non-email channel notifications', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'Alert',
      body: 'SMS alert',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailHandler.getDeliveredEmails()).toHaveLength(0);
  });

  it('should handle multiple email notifications', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'First',
      body: 'First email',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    await eventBus.emit({
      type: 'notification:requested',
      channel: 'email',
      recipient: 'bob@example.com',
      subject: 'Second',
      body: 'Second email',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    const emails = emailHandler.getDeliveredEmails();
    expect(emails).toHaveLength(2);
    expect(emails[0]?.recipient).toBe('alice@example.com');
    expect(emails[1]?.recipient).toBe('bob@example.com');
  });

  it('should clear delivered emails', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test',
      timestamp: new Date(),
    } satisfies NotificationRequestedEvent);

    emailHandler.clearDeliveredEmails();
    expect(emailHandler.getDeliveredEmails()).toHaveLength(0);
  });

  it('should work end-to-end with NotificationService', async () => {
    // Set up both service and email handler on the same EventBus
    const service = new NotificationService(eventBus);
    resetNotificationIdCounter();

    const orderEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 15 },
        ],
        total: 45,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(orderEvent);

    // EmailChannelHandler should have received the dispatched email
    const emails = emailHandler.getDeliveredEmails();
    expect(emails).toHaveLength(1);
    expect(emails[0]?.recipient).toBe('alice@example.com');
    expect(emails[0]?.subject).toContain('Order Confirmation');
    expect(emails[0]?.body).toContain('Widget x3');

    // NotificationService should also track it
    expect(service.getNotificationCount()).toBeGreaterThanOrEqual(1);
  });
});

